21	#include "be_debug.h"
22	#include "be_exec.h"
23	
24	#define OP_NOT_BINARY           TokenNone
25	#define OP_NOT_UNARY            TokenNone
26	#define OP_NOT_ASSIGN           TokenNone
27	#define UNARY_OP_PRIO           3
28	#define ASSIGN_OP_PRIO          16
29	
30	#define FUNC_METHOD             1
31	#define FUNC_ANONYMOUS          2
32	
33	/* get binary operator priority */
34	#define binary_op_prio(op)      (binary_op_prio_tab[cast_int(op) - OptAdd])
35	
36	#define scan_next_token(parser) (be_lexer_scan_next(&(parser)->lexer))
37	#define next_token(parser)      ((parser)->lexer.token)
38	#define next_type(parser)       (next_token(parser).type)
39	#define max(a, b)               ((a) > (b) ? (a) : (b))
40	#define token2str(parser)       be_token2str((parser)->vm, &next_token(parser))
41	#define funcname(parser)        ((parser)->islocal ? "loader" : "main")
42	
43	#define upval_index(v)          ((v) & 0xFF)
44	#define upval_target(v)         ((bbyte)(((v) >> 8) & 0xFF))
45	#define upval_instack(v)        ((bbyte)(((v) >> 16) != 0))
46	#define upval_desc(i, t, s)     (((i) & 0xFF) | (((t) & 0xFF) << 8) \
47	                                | (((s) != 0) << 16))
48	
49	#define match_id(parser, s)     ((s) = _match_id(parser))
50	
51	#define parser_newstr(p, str)   be_lexer_newstr(&(p)->lexer, (str))
52	
53	#define parser_error(p, msg)    be_lexerror(&(p)->lexer, msg)
54	
55	#define push_error(parser, ...) \
56	    parser_error(parser, be_pushfstring(parser->vm, __VA_ARGS__))
57	
58	typedef struct {
59	    blexer lexer;
60	    bvm *vm;
61	    bfuncinfo *finfo;
62	    bclosure *cl;
63	    bbyte islocal;
64	} bparser;
65	
66	#if BE_USE_SCRIPT_COMPILER
67	
68	static void stmtlist(bparser *parser);
69	static void block(bparser *parser, int type);
70	static void expr(bparser *parser, bexpdesc *e);
71	static void sub_expr(bparser *parser, bexpdesc *e, int prio);
72	
73	static const bbyte binary_op_prio_tab[] = {
74	    5, 5, 4, 4, 4, /* + - * / % */
75	    11, 11, 12, 12, 11, 11, /* < <= == != > >= */
76	    7, 9, 8, 6, 6, 10, 13, 14 /*  & | ^ << >> .. && || */
77	};
78	
79	static void match_token(bparser *parser, btokentype type)
80	{
81	    if (next_type(parser) != type) { /* error when token is no match */
82	        btoken *token = &next_token(parser);
83	        const char *s1 = be_tokentype2str(type);
84	        const char *s2 = be_token2str(parser->vm, token);
85	        push_error(parser, "expected '%s' before '%s'", s1, s2);
86	    }
87	    scan_next_token(parser); /* skip this token */
88	}
89	
90	/* Check that the next token is not of type `type` */
91	/* or raise an exception */
92	static void match_notoken(bparser *parser, btokentype type)
93	{
94	    if (next_type(parser) == type) { /* error when token is match */
95	        push_error(parser,
96	            "expected statement before '%s'", token2str(parser));
97	    }
98	}
99	
100	/* check that if the expdesc is a symbol, it is a valid one or raise an exception */
101	static void check_symbol(bparser *parser, bexpdesc *e)
102	{
103	    if (e->type == ETVOID && e->v.s == NULL) { /* error when token is not a symbol */
104	        push_error(parser,
105	            "unexpected symbol near '%s'", token2str(parser));
106	    }
107	}
108	
109	/* check that the value in `e` is valid for a variable, i.e. contains a value or a valid symbol */
110	static void check_var(bparser *parser, bexpdesc *e)
111	{
112	    check_symbol(parser, e); /* check the token is a symbol */
113	    if (e->type == ETVOID) { /* error when symbol is undefined */
114	        int line = parser->lexer.linenumber;
115	        parser->lexer.linenumber = parser->lexer.lastline;
116	        push_error(parser,
117	            "'%s' undeclared (first use in this function)", str(e->v.s));
118	        parser->lexer.linenumber = line;
119	    }
120	}
121	
122	static int match_skip(bparser *parser, btokentype type)
123	{
124	    if (next_type(parser) == type) { /* match */
125	        scan_next_token(parser); /* skip this token */
126	        return btrue;
127	    }
128	    return bfalse;
129	}
130	
131	static bstring* _match_id(bparser *parser)
132	{
133	    if (next_type(parser) == TokenId) {
134	        bstring *str = next_token(parser).u.s;
135	        scan_next_token(parser); /* skip ID */
136	        return str;
137	    }
138	    return NULL;
139	}
140	
141	#if BE_DEBUG_VAR_INFO
142	
143	void begin_varinfo(bparser *parser, bstring *name)
144	{
145	    bvarinfo *var;
146	    bfuncinfo *finfo = parser->finfo;
147	    be_vector_push_c(parser->vm, &finfo->varvec, NULL);
148	    var = be_vector_end(&finfo->varvec);
149	    var->name = name;
150	    var->beginpc = finfo->pc;
151	    var->endpc = 0; /*  */
152	    finfo->proto->varinfo = be_vector_data(&finfo->varvec);
153	    finfo->proto->nvarinfo = be_vector_capacity(&finfo->varvec);
154	}
155	
156	void end_varinfo(bparser *parser, int beginpc)
157	{
158	    bfuncinfo *finfo = parser->finfo;
159	    bblockinfo *binfo = finfo->binfo;
160	    bvarinfo *it = be_vector_data(&finfo->varvec);
161	    bvarinfo *end = be_vector_end(&finfo->varvec);
162	    if (beginpc == -1) /* use block->beginpc by default */
163	        beginpc = binfo->beginpc;
164	    /* skip the variable of the previous blocks */
165	    for (; it->beginpc < beginpc; ++it);
166	    for (; it <= end; ++it) {
167	        if (!it->endpc) /* write to endpc only once */
168	            it->endpc = finfo->pc;
169	    }
170	}
171	
172	#else
173	
174	#define begin_varinfo(parser, name)
175	#define end_varinfo(parser, beginpc) (void)(beginpc)
176	
177	#endif
178	
179	/* Initialize bblockinfo structure */
180	static void begin_block(bfuncinfo *finfo, bblockinfo *binfo, int type)
181	{
182	    binfo->prev = finfo->binfo; /* save previous block */
183	    finfo->binfo = binfo; /* tell parser this is the current block */
184	    binfo->type = (bbyte)type;
185	    binfo->hasupval = 0;
186	    binfo->beginpc = finfo->pc; /* set starting pc for this block */
187	    binfo->nactlocals = (bbyte)be_list_count(finfo->local); /* count number of local variables in previous block */
188	    if (type & BLOCK_LOOP) {
189	        binfo->breaklist = NO_JUMP;
190	        binfo->continuelist = NO_JUMP;
191	    }
192	}
193	
194	static void end_block_ex(bparser *parser, int beginpc)
195	{
196	    bfuncinfo *finfo = parser->finfo;
197	    bblockinfo *binfo = finfo->binfo;
198	    be_code_close(finfo, 0); /* close upvalues */
199	    if (binfo->type & BLOCK_LOOP) {
200	        be_code_jumpto(finfo, binfo->beginpc);
201	        be_code_patchjump(finfo, binfo->breaklist);
202	        be_code_patchlist(finfo, binfo->continuelist, binfo->beginpc);
203	    }
204	    end_varinfo(parser, beginpc);
205	    be_list_resize(parser->vm, finfo->local, binfo->nactlocals); /* remove local variables from this block, they are now out of scope */
206	    finfo->freereg = binfo->nactlocals; /* adjust first free register accordingly */
207	    finfo->binfo = binfo->prev; /* restore previous block */
208	}
209	
210	static void end_block(bparser *parser)
211	{
212	    end_block_ex(parser, -1);
213	}
214	
215	/* Return the name of the source for this parser, could be `string`,
216	   `stdin` or the name of the current function */
217	static bstring* parser_source(bparser *parser)
218	{
219	    if (parser->finfo) {
220	        return parser->finfo->proto->source;
221	    }
222	    return be_newstr(parser->vm, parser->lexer.fname);
223	}
224	
225	/* Initialize a function block and create a new `bprotoˋ */
226	static void begin_func(bparser *parser, bfuncinfo *finfo, bblockinfo *binfo)
227	{
228	    bvm *vm = parser->vm;
229	    bproto *proto = be_newproto(vm);
230	    var_setproto(vm->top, proto);
231	    be_stackpush(vm);
232	    be_vector_init(vm, &finfo->code, sizeof(binstruction)); /* vector for code, vectors are not gced */
233	    proto->code = be_vector_data(&finfo->code);
234	    proto->codesize = be_vector_capacity(&finfo->code);
235	    be_vector_init(vm, &finfo->kvec, sizeof(bvalue)); /* vector for constants */
236	    proto->ktab = be_vector_data(&finfo->kvec);
237	    proto->nconst = be_vector_capacity(&finfo->kvec);
238	    be_vector_init(vm, &finfo->pvec, sizeof(bproto*)); /* vector for subprotos */
239	    proto->ptab = be_vector_data(&finfo->pvec);
240	    proto->nproto = be_vector_capacity(&finfo->pvec);
241	    proto->source = parser_source(parser); /* keep a copy of source for function */
242	    finfo->local = be_list_new(vm); /* list for local variables */
243	    var_setlist(vm->top, finfo->local); /* push list of local variables on the stack (avoid gc) */
244	    be_stackpush(vm);
245	    finfo->upval = be_map_new(vm); /* push a map for upvals on stack */
246	    var_setmap(vm->top, finfo->upval);
247	    be_stackpush(vm);
248	    finfo->prev = parser->finfo; /* init finfo */
249	    finfo->lexer = &parser->lexer;
250	    finfo->proto = proto;
251	    finfo->freereg = 0;
252	    finfo->binfo = NULL;
253	    finfo->pc = 0;
254	    finfo->flags = 0;
255	    parser->finfo = finfo;
256	#if BE_DEBUG_RUNTIME_INFO
257	    be_vector_init(vm, &finfo->linevec, sizeof(blineinfo));
258	    proto->lineinfo = be_vector_data(&finfo->linevec);
259	    proto->nlineinfo = be_vector_capacity(&finfo->linevec);
260	#endif
261	#if BE_DEBUG_VAR_INFO
262	    be_vector_init(vm, &finfo->varvec, sizeof(bvarinfo));
263	    proto->varinfo = be_vector_data(&finfo->varvec);
264	    proto->nvarinfo = be_vector_capacity(&finfo->varvec);
265	#endif
266	    begin_block(finfo, binfo, 0);
267	}
268	
269	/* compute the upval structure */
270	static void setupvals(bfuncinfo *finfo)
271	{
272	    bproto *proto = finfo->proto;
273	    int nupvals = be_map_count(finfo->upval);
274	    if (nupvals) {
275	        bmapnode *node;
276	        bmap *map = finfo->upval;
277	        bmapiter iter = be_map_iter();
278	        bupvaldesc *upvals = be_malloc(
279	                finfo->lexer->vm, sizeof(bupvaldesc) * nupvals);
280	        while ((node = be_map_next(map, &iter)) != NULL) {
281	            uint32_t v = (uint32_t)var_toint(&node->value);
282	            bupvaldesc *uv = upvals + upval_index(v);
283	            uv->idx = upval_target(v);
284	            uv->instack = upval_instack(v);
285	#if BE_DEBUG_VAR_INFO
286	            uv->name = var_tostr(&node->key);
287	#endif
288	        }
289	        proto->upvals = upvals;
290	        proto->nupvals = (bbyte)nupvals;
291	    }
292	}
293	
294	/* Function is complete, finalize bproto */
295	static void end_func(bparser *parser)
296	{
297	    bvm *vm = parser->vm;
298	    bfuncinfo *finfo = parser->finfo;
299	    bproto *proto = finfo->proto;
300	
301	    be_code_ret(finfo, NULL); /* append a return to last code */
302	    end_block(parser); /* close block */
303	    setupvals(finfo); /* close upvals */
304	    proto->code = be_vector_release(vm, &finfo->code); /* compact all vectors and return NULL if empty */
305	    proto->codesize = finfo->pc;
306	    proto->ktab = be_vector_release(vm, &finfo->kvec);
307	    proto->nconst = be_vector_count(&finfo->kvec);
308	    proto->ptab = be_vector_release(vm, &finfo->pvec);
309	    proto->nproto = be_vector_count(&finfo->pvec);
310	#if BE_DEBUG_RUNTIME_INFO
311	    proto->lineinfo = be_vector_release(vm, &finfo->linevec);
312	    proto->nlineinfo = be_vector_count(&finfo->linevec);
313	#endif
314	#if BE_DEBUG_VAR_INFO
315	    proto->varinfo = be_vector_release(vm, &finfo->varvec);
316	    proto->nvarinfo = be_vector_count(&finfo->varvec);
317	#endif
318	    parser->finfo = parser->finfo->prev; /* restore previous `finfo` */
319	    be_stackpop(vm, 2); /* pop upval and local */
320	}
321	
322	/* is the next token a binary operator? If yes return the operator or `OP_NOT_BINARY` */
323	static btokentype get_binop(bparser *parser)
324	{
325	    btokentype op = next_type(parser);
326	    if (op >= OptAdd && op <= OptOr) {
327	        return op;
328	    }
329	    return OP_NOT_BINARY;
330	}
331	
332	/* is the next token a unary operator? If yes return the operator or `OP_NOT_BINARY` */
333	/* operator 'negative' 'not' and 'flip' */
334	static btokentype get_unary_op(bparser *parser)
335	{
336	    btokentype op = next_type(parser);
337	    if (op == OptSub || op == OptNot || op == OptFlip) {
338	        return op; /* operator 'negative' 'not' and 'flip' */
339	    }
340	    return OP_NOT_UNARY;
341	}
342	
343	/* is the next token an assignment operator? If yes return the operator or `OP_NOT_BINARY` */
344	/* `=`, `+=`, ... `>>=` */
345	static btokentype get_assign_op(bparser *parser)
346	{
347	    btokentype op = next_type(parser);
348	    if (op >= OptAssign && op <= OptRsfAssign) {
349	        return op;
350	    }

